mcqs.question:
What will be the output of the following code?

#include <iostream>
using namespace std;

void display(int x) { cout << "Integer: " << x << endl; }
void display(double x) { cout << "Double: " << x << endl; }

int main() {
    display(5);
    display(5.5);
    return 0;
}

Which function call would be ambiguous in the following code?

void func(int a, double b = 0.0) {}
void func(int a) {}

A) func(5);
B) func(5, 10.0);
C) func(5, 10);
D) Both A and C
